#include <stdio.h>
#include <stdlib.h>
#define MAX 100
int max(int a, int b) { return a > b ? a : b; }
int minimumChocolates(int **grid, int R, int C, int i, int j, int **dp) {
    if (i == R) return 0;
    if (dp[i][j] != -1) return dp[i][j];
    int ans = grid[i][j] + minimumChocolates(grid, R, C, i + 1, j, dp);
    if (j > 0) ans = max(ans, grid[i][j] + minimumChocolates(grid, R, C, i + 1, j - 1, dp));
    if (j < C - 1) ans = max(ans, grid[i][j] + minimumChocolates(grid, R, C, i + 1, j + 1, dp));
    dp[i][j] = ans;
    return ans;
}
int maximumChocolates(int **grid, int R, int C) {
    int **dp = (int **)malloc(R * sizeof(int *));
    for (int i = 0; i < R; i++) {
        dp[i] = (int *)malloc(C * sizeof(int));
        for (int j = 0; j < C; j++) dp[i][j] = -1;
    }
    int ans = minimumChocolates(grid, R, C, 0, 0, dp) + minimumChocolates(grid, R, C, 0, C - 1, dp);
    for (int i = 0; i < R; i++) free(dp[i]);
    free(dp);
    return ans;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int R, C;
        scanf("%d %d", &R, &C);
        int **grid = (int **)malloc(R * sizeof(int *));
        for (int i = 0; i < R; i++) {
            grid[i] = (int *)malloc(C * sizeof(int));
            for (int j = 0; j < C; j++) scanf("%d", &grid[i][j]);
        }
        printf("%d\n", maximumChocolates(grid, R, C));
        for (int i = 0; i < R; i++) free(grid[i]);
        free(grid);
    }
    return 0;
}

